+//! # Off-Target Predictor
+//!
+//! ML-based off-target prediction for CRISPR-Cas13.
+//! Uses machine learning models to predict potential off-target cleavage sites.
+
+pub mod error;
+pub mod features;
+pub mod ml_model;
